function buildMessage(user, score) {
  // Each call gets its own stack frame with its own 'user' and 'score'
  const prefix = '[SkillSprint]';
  return `${prefix} ${user} scored ${score}`;
}

console.log(buildMessage('Alice', 95)); // [SkillSprint] Alice scored 95
console.log(buildMessage('Bob', 82));   // [SkillSprint] Bob scored 82
// The two calls are completely isolated stack frames

